export function validateSurfaceReadyEvent(value: unknown): value is SurfaceReadyEvent {
  if (!isRecord(value) || !exactKeys(value, ["metadata", "transport"], [])) return false;
  if (!(validateSurfaceMetadata(value.metadata))) return false;
  if (!(validateSurfaceTransport(value.transport))) return false;
  const surface = value as unknown as SurfaceReadyEvent;
const metadata = surface.metadata;
if (metadata.id === 0n || metadata.owner.worker === 0n || metadata.owner.session === 0n || metadata.generation === 0n || metadata.renderer_epoch === 0 || metadata.plan_id === 0n) return false;
if (!metadata.render_config.some((byte) => byte !== 0) || !metadata.plan_hash.some((byte) => byte !== 0) || !metadata.scene_hash.some((byte) => byte !== 0) || !metadata.decision_hash.some((byte) => byte !== 0)) return false;
if (metadata.width === 0 || metadata.height === 0 || metadata.stride === 0 || metadata.region.width === 0 || metadata.region.height === 0) return false;
const stride = BigInt(metadata.stride);
const minimumStride = BigInt(metadata.width) * 4n;
if (stride < minimumStride || stride % 4n !== 0n) return false;
const layoutBytes = stride * BigInt(metadata.height);
if (metadata.byte_length !== layoutBytes) return false;
const rangeEnd = metadata.byte_offset + metadata.byte_length;
if (rangeEnd > 0xffffffffffffffffn) return false;
let regionLength: bigint;
switch (surface.transport.kind) {
case "OffscreenCanvasCommit": if (surface.transport.canvas === 0n) return false; regionLength = surface.transport.region_length; break;
case "BrowserTransfer": regionLength = surface.transport.transfer_length; break;
case "SharedMemory": if (surface.transport.handle === 0n || surface.transport.release_token === 0n) return false; regionLength = surface.transport.region_length; break;
case "LocalMemory": if (surface.transport.memory_epoch === 0) return false; regionLength = surface.transport.region_length; break;
}
if (rangeEnd > regionLength) return false;
  return true;
}

