export type SurfaceTransport =
  | { kind: "OffscreenCanvasCommit"; canvas: CanvasId; region_length: bigint }
  | { kind: "BrowserTransfer"; slot: number; transfer_kind: BrowserTransferKind; transfer_length: bigint }
  | { kind: "SharedMemory"; handle: PlatformHandle; region_length: bigint; release_token: bigint }
  | { kind: "LocalMemory"; region_length: bigint; memory_epoch: MemoryEpoch }
;

export function validateSurfaceTransport(value: unknown): value is SurfaceTransport {
  if (!isRecord(value) || typeof value.kind !== "string") return false;
  switch (value.kind) {
    case "OffscreenCanvasCommit": return exactKeys(value, ["kind", "canvas", "region_length"], []) && validateCanvasId(value.canvas) && isU64(value.region_length);
    case "BrowserTransfer": return exactKeys(value, ["kind", "slot", "transfer_kind", "transfer_length"], []) && isU16(value.slot) && validateBrowserTransferKind(value.transfer_kind) && isU64(value.transfer_length);
    case "SharedMemory": return exactKeys(value, ["kind", "handle", "region_length", "release_token"], []) && validatePlatformHandle(value.handle) && isU64(value.region_length) && isU64(value.release_token);
    case "LocalMemory": return exactKeys(value, ["kind", "region_length", "memory_epoch"], []) && isU64(value.region_length) && validateMemoryEpoch(value.memory_epoch);
    default: return false;
  }
}

export type Command =
  | { type: "Hello"; payload: HelloCommand }
  | { type: "HelloAccept"; payload: HelloAcceptCommand }
  | { type: "Open"; payload: OpenCommand }
  | { type: "ProvideData"; payload: ProvideDataCommand }
  | { type: "RegisterCanvas"; payload: RegisterCanvasCommand }
  | { type: "ReleaseCanvas"; payload: ReleaseCanvasCommand }
  | { type: "SetViewport"; payload: SetViewportCommand }
  | { type: "Cancel"; payload: CancelCommand }
  | { type: "ReleaseSurface"; payload: ReleaseSurfaceCommand }
  | { type: "CloseSession"; payload: CloseSessionCommand }
  | { type: "Shutdown"; payload: ShutdownCommand }
;

export function validateCommand(value: unknown): value is Command {
  if (!isRecord(value) || !exactKeys(value, ["type", "payload"], []) || typeof value.type !== "string") return false;
  switch (value.type) {
    case "Hello": return validateHelloCommand(value.payload);
    case "HelloAccept": return validateHelloAcceptCommand(value.payload);
    case "Open": return validateOpenCommand(value.payload);
    case "ProvideData": return validateProvideDataCommand(value.payload);
    case "RegisterCanvas": return validateRegisterCanvasCommand(value.payload);
    case "ReleaseCanvas": return validateReleaseCanvasCommand(value.payload);
    case "SetViewport": return validateSetViewportCommand(value.payload);
    case "Cancel": return validateCancelCommand(value.payload);
    case "ReleaseSurface": return validateReleaseSurfaceCommand(value.payload);
    case "CloseSession": return validateCloseSessionCommand(value.payload);
    case "Shutdown": return validateShutdownCommand(value.payload);
    default: return false;
  }
}

export type Event =
  | { type: "Ready"; payload: ReadyEvent }
  | { type: "NeedData"; payload: NeedDataEvent }
  | { type: "DocumentReady"; payload: DocumentReadyEvent }
  | { type: "CanvasReleased"; payload: CanvasReleasedEvent }
  | { type: "CapabilityReported"; payload: CapabilityReportedEvent }
  | { type: "SurfaceReady"; payload: SurfaceReadyEvent }
  | { type: "RequestCancelled"; payload: RequestCancelledEvent }
  | { type: "RequestFailed"; payload: RequestFailedEvent }
  | { type: "SessionClosed"; payload: SessionClosedEvent }
  | { type: "WorkerStopped"; payload: WorkerStoppedEvent }
  | { type: "WorkerFault"; payload: WorkerFaultEvent }
  | { type: "ProtocolFault"; payload: ProtocolFaultEvent }
  | { type: "SurfaceReclaimed"; payload: SurfaceReclaimedEvent }
;

export function validateEvent(value: unknown): value is Event {
  if (!isRecord(value) || !exactKeys(value, ["type", "payload"], []) || typeof value.type !== "string") return false;
  switch (value.type) {
    case "Ready": return validateReadyEvent(value.payload);
    case "NeedData": return validateNeedDataEvent(value.payload);
    case "DocumentReady": return validateDocumentReadyEvent(value.payload);
    case "CanvasReleased": return validateCanvasReleasedEvent(value.payload);
    case "CapabilityReported": return validateCapabilityReportedEvent(value.payload);
    case "SurfaceReady": return validateSurfaceReadyEvent(value.payload);
    case "RequestCancelled": return validateRequestCancelledEvent(value.payload);
    case "RequestFailed": return validateRequestFailedEvent(value.payload);
    case "SessionClosed": return validateSessionClosedEvent(value.payload);
    case "WorkerStopped": return validateWorkerStoppedEvent(value.payload);
    case "WorkerFault": return validateWorkerFaultEvent(value.payload);
    case "ProtocolFault": return validateProtocolFaultEvent(value.payload);
    case "SurfaceReclaimed": return validateSurfaceReclaimedEvent(value.payload);
    default: return false;
  }
}

export interface CommandEnvelope { header: EnvelopeHeader; correlation: Correlation; command: Command }
export interface EventEnvelope { header: EnvelopeHeader; correlation: Correlation; event: Event }

const correlationRequirementMet = (present: boolean, requirement: CorrelationRequirement): boolean => requirement === "required" ? present : requirement === "optional" ? true : !present;
const validateDescriptorCorrelation = (correlation: Correlation, descriptor: MessageDescriptor): boolean => {
if (correlation.worker === 0n || correlation.session === 0n || correlation.request === 0n || correlation.generation === 0n) return false;
return correlationRequirementMet(true, descriptor.correlation_shape.worker)
&& correlationRequirementMet(correlation.session !== undefined, descriptor.correlation_shape.session)
&& correlationRequirementMet(correlation.request !== undefined, descriptor.correlation_shape.request)
&& correlationRequirementMet(correlation.generation !== undefined, descriptor.correlation_shape.generation);
};
const validateTransferBinding = (message: Command | Event, transferSlots: number, descriptor: MessageDescriptor): boolean => {
if (!isU16(transferSlots) || transferSlots > MAX_TRANSFER_SLOTS || transferSlots < descriptor.min_transfer_slots || transferSlots > descriptor.max_transfer_slots) return false;
switch (message.type) {
case "ProvideData": return message.payload.segments.length === transferSlots && message.payload.segments.every((segment, index) => segment.slot === index);
case "RegisterCanvas": return message.payload.transfer_slot < transferSlots;
case "SurfaceReady": {
const transport = message.payload.transport;
switch (transport.kind) {
case "BrowserTransfer": return transferSlots === 1 && transport.slot < transferSlots;
case "SharedMemory": return transferSlots === 1;
case "OffscreenCanvasCommit":
case "LocalMemory": return transferSlots === 0;
}
}
default: return true;
}
};
const validatePayloadCorrelation = (correlation: Correlation, message: Command | Event): boolean => {
switch (message.type) {
case "SetViewport": return correlation.generation === message.payload.viewport.generation;
case "Cancel": return correlation.request === message.payload.target;
case "Ready": return correlation.worker === message.payload.worker;
case "DocumentReady": return correlation.session === undefined || correlation.session === message.payload.session;
case "SurfaceReady": return correlation.worker === message.payload.metadata.owner.worker
&& correlation.session === message.payload.metadata.owner.session
&& correlation.generation === message.payload.metadata.generation;
case "RequestCancelled": return correlation.request === message.payload.target;
case "SessionClosed": return correlation.session === message.payload.session;
case "WorkerStopped": return correlation.worker === message.payload.worker;
default: return true;
}
};
const validateEnvelopeDescriptor = (header: EnvelopeHeader, correlation: Correlation, message: Command | Event, kind: MessageKind, transferSlots: number): boolean => {
const descriptor = descriptorById(header.message_type);
return descriptor !== undefined
&& descriptor.kind === kind
&& descriptor.name === message.type
&& validateDescriptorCorrelation(correlation, descriptor)
&& validateTransferBinding(message, transferSlots, descriptor)
&& validatePayloadCorrelation(correlation, message);
};
export function validateEnvelopeHeaderForMinor(value: unknown, negotiatedMinor: number): value is EnvelopeHeader {
return Number.isInteger(negotiatedMinor)
&& negotiatedMinor >= MIN_COMPATIBLE_MINOR
&& negotiatedMinor <= PROTOCOL_MINOR
&& validateEnvelopeHeader(value)
&& value.minor === negotiatedMinor;
}
export function validateCommandEnvelope(value: unknown, transferSlots = 0, negotiatedMinor: number = PROTOCOL_MINOR): value is CommandEnvelope {
if (!isRecord(value) || !exactKeys(value, ["header", "correlation", "command"], []) || !validateEnvelopeHeaderForMinor(value.header, negotiatedMinor) || !validateCorrelation(value.correlation) || !validateCommand(value.command)) return false;
const envelope = value as unknown as CommandEnvelope;
return validateEnvelopeDescriptor(envelope.header, envelope.correlation, envelope.command, "command", transferSlots);
}
export function validateEventEnvelope(value: unknown, transferSlots = 0, negotiatedMinor: number = PROTOCOL_MINOR): value is EventEnvelope {
if (!isRecord(value) || !exactKeys(value, ["header", "correlation", "event"], []) || !validateEnvelopeHeaderForMinor(value.header, negotiatedMinor) || !validateCorrelation(value.correlation) || !validateEvent(value.event)) return false;
const envelope = value as unknown as EventEnvelope;
return validateEnvelopeDescriptor(envelope.header, envelope.correlation, envelope.event, "event", transferSlots);
}
